import{c as n}from"./app.8935f5f1.js";const s={},t=n('<p>项目结构</p><p>Vuex 并不限制你的代码结构。但是，它规定了一些需要遵守的规则：</p><ol><li>应用层级的状态应该集中到单个 store 对象中。</li><li>提交 <strong>mutation</strong> 是更改状态的唯一方法，并且这个过程是同步的。</li><li>异步逻辑都应该封装到 <strong>action</strong> 里面。</li></ol><p>只要你遵守以上规则，如何组织代码随你便。如果你的 store 文件太大，只需将 action、mutation 和 getter 分割到单独的文件。</p><p>对于大型应用，我们会希望把 Vuex 相关代码分割到模块中。下面是项目结构示例：</p><div class="language-bash ext-sh"><pre class="language-bash"><code>├── index.html\n├── main.js\n├── api\n│   └── <span class="token punctuation">..</span>. <span class="token comment"># 抽取出API请求</span>\n├── components\n│   ├── App.vue\n│   └── <span class="token punctuation">..</span>.\n└── store\n    ├── index.js          <span class="token comment"># 我们组装模块并导出 store 的地方</span>\n    ├── actions.js        <span class="token comment"># 根级别的 action</span>\n    ├── mutations.js      <span class="token comment"># 根级别的 mutation</span>\n    └── modules\n        ├── cart.js       <span class="token comment"># 购物车模块</span>\n        └── products.js   <span class="token comment"># 产品模块</span>\n</code></pre></div>',6);s.render=function(n,s){return t};export{s as default};
